function [ dataf ] = pf2_bpf_fir( data,fs,lowF,highF,Nf,restoreMean)% inputs ------------------------% data: data to be filtered% filtOrder: filter order% fs: sampling freq.% lowF: highpass cut-off frequency% highF: lowpass cutoff frequency% Nf: filter Length% restoreMean: add back in 0 frequency data% outputs -----------------------% dataf: filtered data%--------------------------------% bpf function designs lowpass FIR filter with the specified cut-off frequencies and length.% It filters the data columnwise as its output%--------------------------------if(nargin<6)   restoreMean=false; end[Mini,Nini]=size(data);if Mini==1 %if the data is a row vector converts it to column vector    data=data';end[M,N]=size(data);%-----------------------------------------------------------------% Band-pass Filter design%-----------------------------------------------------------------half_fs = fs/2;    %half of sampling freq. equal to pi[b,a] = fir1(Nf,[lowF highF]/half_fs);if(size(data,1)>3*Nf)    try                dataf=filtfilt(b,a,data);    catch        dataf=nantolerant_filtfilt(b,a,data);    endelse    dataf=nan(size(data));     warning('LPF: Datasize must be larger than 3*filter length (%i samples)',Nf);endif(restoreMean)   dataf=dataf+nanmean(data,1); endif Mini==1 %if the data is a row vector converts it to column vector    dataf=dataf';endendfunction dataf=nantolerant_filtfilt(b,a,data)    datamask=isnan(data)|isinf(data);        data(datamask)=nanmedian(data(:));    for i=1:size(data,2)       data(datamask(:,i),i)=nanmedian(data(:,i));     end    data(isnan(data))=0;        dataf=filtfilt(b,a,data);        dataf(datamask)=nan;end